730				attemptProvider := spec.Provider
731				if resolvedProvider != "" {
732					attemptProvider = resolvedProvider
733				}
734				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
735					Harness:           resolvedHarness,
736					Model:             resolvedModel,
737					Provider:          attemptProvider,
738					ModelRef:          spec.ModelRef,
739					Profile:           rcfg.Profile(),
740					Effort:            spec.Effort,
741					MinPower:          requestedMinPower,
742					OpaquePassthrough: spec.OpaquePassthrough,
743				})
744				beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
745				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
746					BeadEvents: beadStore,
747					BeadCancel: beadStore,
748				}, gitOps)
749				if err != nil && res == nil {
750					return agent.ExecuteBeadReport{}, err
751				}
752				// Preserve operator-cancel results as-is; the worker has already
753				// classified them (preserved / operator_cancel / preserved_needs_review)
754				// and overriding here would lose the cancel signal.
755				operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
756				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
757					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
758						err = landErr
759					}
760				} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
761					res.Outcome = "no-changes"
762					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
763				} else if res != nil && res.ExitCode != 0 && !operatorCancel {
764					res.Outcome = "preserved"
765					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
766				}
767				// Safety net: commit any leftover evidence files that Land()
768				// did not pick up (e.g. HEAD was detached, or no land ran).
769				if res != nil && res.AttemptID != "" {
770					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
771				}
772				if err != nil {
773					return agent.ExecuteBeadReport{}, err
774				}
775				return agent.ExecuteBeadReport{
